\vspace{-\intextsep}
\begin{algorithm}[H]
\caption{Constrained ``fill-in-the-gap''}
\begin{algorithmic}[1]
\Function{ConstrainedFill}{\texttt{promptInstruction, numMasked}}
    \State \texttt{prompt} $\gets$ \texttt{promptInstruction}
    \For{each group of \texttt{numMasked} paragraphs}
        \State \texttt{firstParagraph} $\gets$ \textit{generate text using the LLM to fill the first paragraph in the group based on its first sentence}
        \State \texttt{prompt} $\gets$ \texttt{prompt + firstParagraph}
        \State \texttt{middleParagraphs} $\gets$ \textit{generate text using the LLM to fill all paragraphs in the group besides the first and last}
        \State \texttt{prompt} $\gets$ \texttt{prompt + middleParagraphs}
        \State \texttt{lastParagraph} $\gets$ \textit{generate text using the LLM to fill the last paragraph based on its last sentence}
        \State \texttt{prompt} $\gets$ \texttt{prompt + lastParagraph}
    \EndFor
    \State \textbf{return} \texttt{prompt}
\EndFunction
\end{algorithmic}
\end{algorithm}
\begin{enumerate}[noitemsep]
    \item \textbf{Free Generation Example Prompt}: 
    \begin{tcolorbox}[colback=white, arc=4pt]
    Take a look at the story and generate text according to the instruction in brackets []. Only return the generated parts. Here is the story:
    \\\textit{Text from previous generation}
    \\\textit{Text from previous generation}
    \\\textit{Text from previous generation}
    \\$[\text{Generate text here}]$
    \end{tcolorbox}
    \item \textbf{``Fill-in-the-gap'' Example Prompt (Fill 1 paragraphs)}: 
    \begin{tcolorbox}[colback=white, arc=4pt]
    Take a look at the story and generate text according to the instruction in brackets []. Only return the generated parts. Here is the story:
    \\\textit{Original paragraph text}
    \\\textit{Text from previous generation}
    \\\textit{Original paragraph text}
    \\$[\text{Generate paragraph of approximately 94 tokens here}]$
    \\\textit{Original paragraph text}
    \end{tcolorbox}

    \item \textbf{Constrained ``Fill-in-the-gap'' Example Prompt (Fill 3 paragraphs)}: 
    \begin{tcolorbox}[colback=white, arc=4pt]
    Take a look at the story and generate text according to the instruction in brackets []. Only return the generated parts. Here is the story:
    \\\textit{Text from previous generation}
    \\\textit{Text from previous generation}
    \\\textit{Text from previous generation}
    \\\textit{Original first sentence of paragraph 1}
    \\$[\text{Complete preceding paragraph using approximately 67 tokens}]$
    \\$[\text{Generate paragraph of approximately 129 tokens here}]$
    \\$[\text{Complete following paragraph using approximately 87 tokens}]$
    \\\textit{Original last sentence of paragraph 3}
    \end{tcolorbox}
\end{enumerate}



